sp_angular_provider.script:
/* Long text will be truncated and an ellipsis added based on parameter dtechEndIndex.
Usage in a widget's HTML:
	AngularJS normalizes case-sensitive camelCase to case-insensitive kebab-case for the DOM.
		<span dtech-show-ellipsis-with-tooltip 
			dtech-custom-class="{{data.tooltipCustomClass}}"
			dtech-placement="{{data.tooltipPlacement}}"
			dtech-prefix-text="{{data.number}}"
			dtech-main-text="{{data.f.title}}"
			dtech-end-index="{{data.lengthToAddEllipsis}}">
       </span>

	Of the 5 parameters, dtechCustomClass, dtechPlacement and dtechPrefixText are not required.

	dtechCustomClass should be a string that is found as a CSS Selector (theme or widget); can be omitted from widget's HTML
	dtechEndIndex can be a number or string 0-9,
	dtechMainText should be a string,
	dtechPlacement should be a strings, see UI Bootstrap's web site for values, defaults to top if omitted from widget's HTML
	dtechPrefixText should be a string; can be omitted from widget's HTML
//
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
// Script Continued Below
// 2.7.1 | 2021-12-10 | mmcc | STRY0115408 - Long text needs to be shortened and have an ellipsis added 
//										   with uib-tooltip control to show full text
*/
function dtechShowEllipsisWithTooltip() {
	var htmlTemplate = 
		'<span tooltip-enable="{{outputTextTrim.length > dtechEndIndex}}"' +
		'tooltip-placement="{{dtechPlacement}}" tooltip-class="{{dtechCustomClass}}"' +
		'uib-tooltip="{{outputTextFull}}">' +
		'{{outputTextTrim}}</span>';


	var jsController =
		function($scope) {
			$scope.outputTextTrim = '';
			$scope.outputTextFull = '';

			function init() {
				if ($scope.dtechPrefixText == undefined) {
					$scope.dtechPrefixText = '';
				} else {
					$scope.dtechPrefixText = $scope.dtechPrefixText.trim();
				}

				if ($scope.dtechPrefixText.length > 0) {
					$scope.outputTextFull = $scope.dtechPrefixText + ': ' + $scope.dtechMainText.trim();
				} else {
					$scope.outputTextFull = $scope.dtechMainText.trim();
				}

				$scope.outputTextTrim = $scope.outputTextFull.substring(0, $scope.dtechEndIndex);

				if ($scope.outputTextTrim.length == +$scope.dtechEndIndex) {
					$scope.outputTextTrim = $scope.outputTextTrim.trim() + '...';
				}
			}

			init();

			// call init() if either variable on the $scope changes; e.g., changing nodes on OH view
			$scope.$watchGroup(['dtechPrefixText', 'dtechMainText'], init);
		};

	return {
		restrict: 'A',
		scope: {
			dtechCustomClass: '@',
			dtechEndIndex: '@',
			dtechMainText: '@',
			dtechPlacement: '@',
			dtechPrefixText: '@',
		},
		replace: true,
		controller: jsController,
		template: htmlTemplate
	};
}
